import React, { useEffect, useMemo, useRef, useState } from 'react'
import { createRoot } from 'react-dom/client'
import { PUZZLES, PUZZLE_OPTIONS } from './data/puzzles.js'
import {
  areAdjacent,
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  getIslandAt,
  isVictory
} from './utils/hashiLogic.js'

const GRID = 40
const WIDTH = 800
const HEIGHT = 600

function App() {
  const [difficulty, setDifficulty] = useState('Easy')
  const islands = useMemo(() => PUZZLES[difficulty].islands, [difficulty])

  const [bridges, setBridges] = useState(() => new Map())
  const [selectedId, setSelectedId] = useState(null)
  const [cursorId, setCursorId] = useState(0)
  const [error, setError] = useState(null)

  const svgRef = useRef(null)

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges])
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges])

  useEffect(() => {
    // On puzzle change: reset bridges + selection + error, keep islands.
    setBridges(new Map())
    setSelectedId(null)
    setError(null)
    setCursorId(islands[0]?.id ?? 0)
  }, [difficulty])

  function clearOnValid(valid) {
    if (valid) setError(null)
  }

  function applyBridgeDelta(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta)
    if (!res.valid) {
      setError(res.error)
      return false
    }

    const key = canonicalBridgeKey(from, to)
    const existing = bridges.get(key) ?? 0
    const next = Math.max(0, Math.min(2, existing + delta))

    const nextMap = new Map(bridges)
    if (next === 0) nextMap.delete(key)
    else nextMap.set(key, next)
    setBridges(nextMap)
    clearOnValid(true)
    return true
  }

  function cycleBridge(from, to) {
    const key = canonicalBridgeKey(from, to)
    const existing = bridges.get(key) ?? 0
    const target = (existing + 1) % 3 // 0->1->2->0
    const delta = target - existing
    return applyBridgeDelta(from, to, delta)
  }

  function toggleBridge(from, to) {
    const key = canonicalBridgeKey(from, to)
    const existing = bridges.get(key) ?? 0
    const target = existing === 0 ? 1 : 0
    const delta = target - existing
    return applyBridgeDelta(from, to, delta)
  }

  function onIslandActivate(island) {
    // First click selects.
    if (selectedId == null || selectedId === island.id) {
      setSelectedId(island.id)
      setCursorId(island.id)
      return
    }
    // Second click on a different island attempts toggle.
    const from = islands.find((i) => i.id === selectedId)
    const to = island
    const ok = cycleBridge(from, to)
    if (ok) {
      setSelectedId(to.id)
      setCursorId(to.id)
    }
  }

  function onIslandContextToggle(island, e) {
    e.preventDefault()
    e.stopPropagation()
    if (selectedId == null || selectedId === island.id) {
      setSelectedId(island.id)
      setCursorId(island.id)
      return
    }
    const from = islands.find((i) => i.id === selectedId)
    const to = island
    const ok = toggleBridge(from, to)
    if (ok) {
      setSelectedId(to.id)
      setCursorId(to.id)
    }
  }

  function nearestInDirection(from, dx, dy) {
    let best = null
    for (const isl of islands) {
      if (isl.id === from.id) continue
      if (dx !== 0) {
        if (isl.y !== from.y) continue
        const dd = (isl.x - from.x) * dx
        if (dd <= 0) continue
        // must be adjacent in that direction (no island between)
        if (!areAdjacent(islands, from, isl)) continue
        if (best == null || dd < best.dd) best = { isl, dd }
      } else {
        if (isl.x !== from.x) continue
        const dd = (isl.y - from.y) * dy
        if (dd <= 0) continue
        if (!areAdjacent(islands, from, isl)) continue
        if (best == null || dd < best.dd) best = { isl, dd }
      }
    }
    return best?.isl ?? null
  }

  useEffect(() => {
    function onKeyDown(e) {
      const activeTag = document.activeElement?.tagName?.toLowerCase()
      if (activeTag === 'select' || activeTag === 'button') return

      const cur = islands.find((i) => i.id === cursorId) || islands[0]
      if (!cur) return

      if (e.key === 'Escape') {
        setSelectedId(null)
        setError(null)
        return
      }

      if (e.key === 'Enter') {
        if (selectedId == null) {
          setSelectedId(cur.id)
        } else {
          const sel = islands.find((i) => i.id === selectedId)
          if (sel && sel.id !== cur.id) {
            const ok = cycleBridge(sel, cur)
            if (ok) setSelectedId(cur.id)
          } else {
            setSelectedId(cur.id)
          }
        }
        return
      }

      let dir = null
      if (e.key === 'ArrowLeft') dir = [-1, 0]
      if (e.key === 'ArrowRight') dir = [1, 0]
      if (e.key === 'ArrowUp') dir = [0, -1]
      if (e.key === 'ArrowDown') dir = [0, 1]
      if (!dir) return

      e.preventDefault()
      const nxt = nearestInDirection(cur, dir[0], dir[1])
      if (nxt) setCursorId(nxt.id)
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [cursorId, islands, selectedId, bridges])

  function onSvgClick(e) {
    // click empty space clears selection
    if (e.target === svgRef.current) {
      setSelectedId(null)
    }
  }

  const islandById = useMemo(() => {
    const m = new Map()
    for (const i of islands) m.set(i.id, i)
    return m
  }, [islands])

  const lines = useMemo(() => {
    const arr = []
    for (const [key, n] of bridges.entries()) {
      if (!n) continue
      const [x1, y1, x2, y2] = key.split(',').map(Number)
      arr.push({ x1, y1, x2, y2, n, key })
    }
    return arr
  }, [bridges])

  return (
    <div
      style={{
        margin: 0,
        padding: 0,
        background: '#000',
        color: '#00ff66',
        fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace',
        minHeight: '100vh',
        overflow: 'hidden'
      }}
    >
      <div style={{ position: 'absolute', left: 0, top: 0, padding: 8 }}>
        <label>
          Puzzle:{' '}
          <select
            value={difficulty}
            onChange={(e) => setDifficulty(e.target.value)}
            style={{
              background: '#000',
              color: '#00ff66',
              border: '1px solid #00ff66',
              fontFamily: 'inherit'
            }}
          >
            {PUZZLE_OPTIONS.map((opt) => (
              <option key={opt} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        </label>
        <button
          onClick={() => {
            setBridges(new Map())
            setSelectedId(null)
            setError(null)
          }}
          style={{
            marginLeft: 8,
            background: '#000',
            color: '#00ff66',
            border: '1px solid #00ff66',
            fontFamily: 'inherit',
            padding: '2px 6px',
            cursor: 'pointer'
          }}
        >
          Reset
        </button>
        {error ? <div className="error-message" style={{ marginTop: 6, color: '#00ff66' }}>{error}</div> : null}
        {victory ? <div className="victory-banner" style={{ marginTop: 6, color: '#00ff66', border: '1px solid #00ff66', display: 'inline-block', padding: '2px 6px' }}>SOLVED!</div> : null}
      </div>

      <svg
        ref={svgRef}
        width={WIDTH}
        height={HEIGHT}
        onClick={onSvgClick}
        style={{
          position: 'absolute',
          left: 0,
          top: 0,
          display: 'block',
          background: '#000'
        }}
      >
        {/* Bridges */}
        {lines.map(({ x1, y1, x2, y2, n, key }) => {
          const px1 = x1 * GRID
          const py1 = y1 * GRID
          const px2 = x2 * GRID
          const py2 = y2 * GRID

          const isHoriz = py1 === py2
          const offset = 4
          const stroke = '#00ff66'
          const common = {
            stroke,
            strokeWidth: 3,
            strokeLinecap: 'round'
          }

          const handleContext = (e) => {
            e.preventDefault()
            e.stopPropagation()
            // Ctrl+click on bridge toggles too
            const a = getIslandAt(islands, x1, y1)
            const b = getIslandAt(islands, x2, y2)
            if (a && b) {
              const ok = toggleBridge(a, b)
              if (ok) {
                setSelectedId(b.id)
                setCursorId(b.id)
              }
            }
          }

          const handleClick = (e) => {
            if (e.ctrlKey) {
              handleContext(e)
            }
          }

          if (n === 1) {
            return (
              <line
                key={key}
                x1={px1}
                y1={py1}
                x2={px2}
                y2={py2}
                {...common}
                onContextMenu={handleContext}
                onClick={handleClick}
              />
            )
          }

          // double bridge: two parallel lines
          const dx = isHoriz ? 0 : offset
          const dy = isHoriz ? offset : 0
          return (
            <g key={key} onContextMenu={handleContext} onClick={handleClick}>
              <line x1={px1 - dx} y1={py1 - dy} x2={px2 - dx} y2={py2 - dy} {...common} />
              <line x1={px1 + dx} y1={py1 + dy} x2={px2 + dx} y2={py2 + dy} {...common} />
            </g>
          )
        })}

        {/* Cursor (must not be a circle) */}
        {(() => {
          const cur = islandById.get(cursorId)
          if (!cur) return null
          const px = cur.x * GRID
          const py = cur.y * GRID
          return (
            <rect
              x={px - 18}
              y={py - 18}
              width={36}
              height={36}
              fill="none"
              stroke={selectedId === cursorId ? '#00ff66' : '#00aa44'}
              strokeWidth={2}
              strokeDasharray={selectedId === cursorId ? '0' : '4 3'}
            />
          )
        })()}

        {/* Islands */}
        {islands.map((isl) => {
          const px = isl.x * GRID
          const py = isl.y * GRID
          const isSelected = selectedId === isl.id
          const curCount = counts.get(isl.id) ?? 0

          return (
            <g
              key={isl.id}
              transform={`translate(${px},${py})`}
              style={{ cursor: 'pointer' }}
              onClick={(e) => {
                e.stopPropagation()
                onIslandActivate(isl)
              }}
              onContextMenu={(e) => onIslandContextToggle(isl, e)}
            >
              <circle
                cx={0}
                cy={0}
                r={14}
                fill="#000"
                stroke={isSelected ? '#00ff66' : '#00aa44'}
                strokeWidth={2}
              />
              <text
                x={0}
                y={5}
                textAnchor="middle"
                fontSize={14}
                fill="#00ff66"
              >
                {isl.value}
              </text>
              <text
                x={0}
                y={26}
                textAnchor="middle"
                fontSize={10}
                fill="#00aa44"
              >
                {curCount}/{isl.value}
              </text>
            </g>
          )
        })}
      </svg>
    </div>
  )
}

createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
)
